#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct Point {
	double x, y;
};

double distance(Point const& p1, Point const& p2) {
	return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

// Function to compute the cross product of vectors OA and OB
double crossProduct(const Point &O, const Point &A, const Point &B) {
	return (A.x - O.x) * (B.y - O.y) - (A.y - O.y) * (B.x - O.x);
}

// Function to compute the convex hull using Graham's scan algorithm
std::vector<Point> grahamScan(const std::vector<Point>& points) {
	if (points.size() <= 1) return points;

	// Find the point with the lowest y-coordinate, break ties by x-coordinate
	Point p0 = *min_element(points.begin(), points.end(),
	                        [](const Point &a, const Point &b) { 
	                            return a.y < b.y || (a.y == b.y && a.x < b.x); });

	// Sort points based on polar angle with respect to p0
	std::sort(points.begin() + 1, points.end(), [&](const Point &a, const Point &b) {
		double cp = crossProduct(p0, a, b);
		return (cp > 0 || (cp == 0 && distance(p0, a) < distance(p0, b)));
	});

	std::vector<Point> hull;
	hull.push_back(points[0]);
	hull.push_back(points[1]);

	for (size_t i = 2; i < points.size(); ++i) {
		while (hull.size() > 1 && crossProduct(hull[hull.size()-2], hull.back(), points[i]) <= 0) {
			hull.pop_back();
		}
		hull.push_back(points[i]);
	}

	return hull;
}

double convexHullPerimeter(const std::vector<Point>& points) {
	if (points.empty()) return 0.0;

	std::vector<Point> sortedPoints = points; // Copy to sort

	// Parallelize sorting using OpenMP
	#pragma omp parallel for
	for (int i = 1; i < sortedPoints.size(); ++i) {
		Point p0 = *min_element(sortedPoints.begin(), sortedPoints.end(),
		                        [](const Point &a, const Point &b) { 
		                            return a.y < b.y || (a.y == b.y && a.x < b.x); });
		std::sort(sortedPoints.begin() + 1, sortedPoints.end(), [&](const Point &a, const Point &b) {
			double cp = crossProduct(p0, a, b);
			return (cp > 0 || (cp == 0 && distance(p0, a) < distance(p0, b)));
		});
	}

	std::vector<Point> hull = grahamScan(sortedPoints);

	if (hull.size() <= 2) return 0.0;

	double perimeter = 0.0;
	for (size_t i = 1; i < hull.size(); ++i) {
		perimeter += distance(hull[i-1], hull[i]);
	}
	// Add the last edge to complete the polygon
	perimeter += distance(hull.back(), hull.front());

	return perimeter;
}
